using System;
using System.Data.SqlClient;

public class DatabaseConnectionHelper
{
    private static readonly string connectionString = "Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;";

    public static SqlConnection GetConnection()
    {
        return new SqlConnection(connectionString);
    }

    public static void ExecuteQuery(string query)
    {
        using (SqlConnection connection = GetConnection())
        {
            try
            {
                connection.Open();
                SqlCommand command = new SqlCommand(query, connection);
                command.ExecuteNonQuery();
            }
            catch (Exception ex)
            {
                Console.WriteLine("Error executing query: " + ex.Message);
            }
        }
    }

    public static object ExecuteScalar(string query)
    {
        using (SqlConnection connection = GetConnection())
        {
            try
            {
                connection.Open();
                SqlCommand command = new SqlCommand(query, connection);
                return command.ExecuteScalar();
            }
            catch (Exception ex)
            {
                Console.WriteLine("Error executing scalar: " + ex.Message);
                return null;
            }
        }
    }

    public static void ExecuteReader(string query, Action<SqlDataReader> readerAction)
    {
        using (SqlConnection connection = GetConnection())
        {
            try
            {
                connection.Open();
                SqlCommand command = new SqlCommand(query, connection);
                SqlDataReader reader = command.ExecuteReader();
                while (reader.Read())
                {
                    readerAction(reader);
                }
                reader.Close();
            }
            catch (Exception ex)
            {
                Console.WriteLine("Error executing reader: " + ex.Message);
            }
        }
    }
